queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasWater_Sports ?child ; p:hasBeach_Resorts ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  ?child p:Description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Beach_Resorts } }
  FILTER(?nf = ?total)
}

